61	                        "description": "Create a new browser session for an agent goal",
62	                        "inputSchema": {
63	                            "type": "object",
64	                            "properties": {
65	                                "goal_id": { "type": "string", "description": "Goal ID this session belongs to" },
66	                                "start_url": { "type": "string", "description": "Initial URL to load (default: about:blank)" }
67	                            },
68	                            "required": ["goal_id"]
69	                        }
70	                    },
71	                    {
72	                        "name": "navigate",
73	                        "description": "Navigate the browser to a URL",
74	                        "inputSchema": {
75	                            "type": "object",
76	                            "properties": {
77	                                "url": { "type": "string", "description": "The URL to navigate to" },
78	                                "session_id": { "type": "string", "description": "Browser session ID" }
79	                            },
80	                            "required": ["url", "session_id"]
81	                        }
82	                    },
83	                    {
84	                        "name": "click",
85	                        "description": "Click an element on the page",
86	                        "inputSchema": {
87	                            "type": "object",
88	                            "properties": {
89	                                "selector": { "type": "string", "description": "CSS selector for the element" },
90	                                "session_id": { "type": "string", "description": "Browser session ID" }
91	                            },
92	                            "required": ["selector", "session_id"]
93	                        }
94	                    },
95	                    {
96	                        "name": "type_text",
97	                        "description": "Type text into an input element",
98	                        "inputSchema": {
99	                            "type": "object",
100	                            "properties": {
101	                                "selector": { "type": "string", "description": "CSS selector for the input" },
102	                                "value": { "type": "string", "description": "Text to type" },
