105	                            "required": ["selector", "value", "session_id"]
106	                        }
107	                    },
108	                    {
109	                        "name": "scroll",
110	                        "description": "Scroll the page",
111	                        "inputSchema": {
112	                            "type": "object",
113	                            "properties": {
114	                                "session_id": { "type": "string", "description": "Browser session ID" },
