150	                        "inputSchema": {
151	                            "type": "object",
152	                            "properties": {
153	                                "session_id": { "type": "string", "description": "Browser session ID" },
154	                                "action_type": { "type": "string", "description": "Action type: click, type, scroll, select, navigate, submit, wait, screenshot" },
155	                                "selector": { "type": "string", "description": "CSS selector for the target element" },
156	                                "value": { "type": "string", "description": "Value for type/select/scroll actions" }
