168	                            },
169	                            "required": ["goal_id"]
170	                        }
171	                    },
172	                    {
173	                        "name": "create_goal",
174	                        "description": "Create a new goal for the agent to pursue",
175	                        "inputSchema": {
176	                            "type": "object",
177	                            "properties": {
178	                                "description": { "type": "string", "description": "What the agent needs to accomplish" },
179	                                "context": { "type": "string", "description": "Additional context for the goal" },
180	                                "max_steps": { "type": "integer", "description": "Maximum action steps allowed" }
