354	    async fn tool_screenshot(&self, args: &Value) -> Result<String, String> {
355	        let session_id = Self::str_arg(args, "session_id").ok_or("session_id required")?;
356	        let full_page = args
357	            .get("full_page")
358	            .and_then(serde_json::Value::as_bool)
359	            .unwrap_or(false);
360	
361	        let mut client = self.client.clone_client();
362	        let req = tonic::Request::new(ans_proto::ans::ScreenshotRequest {
363	            session_id: session_id.into(),
364	            format: "png".into(),
365	            quality: 80,
366	            full_page,
367	            arrow_shm_key: String::new(),
368	        });
369	
370	        let resp = client
371	            .capture_screenshot(req)
372	            .await
373	            .map_err(|e| format!("gRPC error: {e}"))?
374	            .into_inner();
375	
376	        Ok(serde_json::to_string_pretty(&json!({
377	            "success": resp.success,
378	            "size_bytes": resp.size_bytes,
379	            "format": resp.format,
380	            "data_base64_len": resp.data.len(),
381	        }))
382	        .unwrap_or_else(|e| format!("serialization error: {e}")))
383	    }
