411	    async fn tool_check_goal(&self, args: &Value) -> Result<String, String> {
412	        let goal_id = Self::str_arg(args, "goal_id").ok_or("goal_id required")?;
413	
414	        let mut client = self.client.clone_client();
415	        let req = tonic::Request::new(ans_proto::ans::GoalStateRequest {
416	            goal_id: goal_id.into(),
417	        });
418	
419	        let resp = client
420	            .get_goal_state(req)
421	            .await
422	            .map_err(|e| format!("gRPC error: {e}"))?
423	            .into_inner();
424	
425	        Ok(serde_json::to_string_pretty(&json!({
426	            "goal_id": resp.goal_id,
427	            "description": resp.description,
428	            "status": resp.status,
429	            "progress": resp.progress,
430	            "sub_goals": resp.sub_goals.len(),
431	            "created_at": resp.created_at,
432	        }))
433	        .unwrap_or_else(|e| format!("serialization error: {e}")))
434	    }
