436	    async fn tool_create_goal(&self, args: &Value) -> Result<String, String> {
437	        let description = Self::str_arg(args, "description").ok_or("description required")?;
438	        let context_str = Self::str_arg(args, "context").unwrap_or("");
439	        let max_steps = args
440	            .get("max_steps")
441	            .and_then(serde_json::Value::as_i64)
442	            .unwrap_or(100) as i32;
443	
444	        let mut context = std::collections::HashMap::new();
445	        if !context_str.is_empty() {
446	            context.insert("context".into(), context_str.into());
447	        }
448	
449	        let mut client = self.client.clone_client();
450	        let req = tonic::Request::new(ans_proto::ans::CreateGoalRequest {
451	            description: description.into(),
452	            context,
453	            max_budget_cents: 500,
454	            max_steps,
455	        });
456	
457	        let resp = client
458	            .create_goal(req)
459	            .await
460	            .map_err(|e| format!("gRPC error: {e}"))?
461	            .into_inner();
462	
463	        Ok(serde_json::to_string_pretty(&json!({
464	            "goal_id": resp.goal_id,
465	            "description": resp.description,
466	            "status": resp.status,
467	            "progress": resp.progress,
468	        }))
469	        .unwrap_or_else(|e| format!("serialization error: {e}")))
470	    }
471	}
