473	// ── JSON-RPC helpers ──────────────────────────────────────────────
474	
475	fn json_rpc_result(id: Option<Value>, result: Value) -> Value {
476	    json!({
477	        "jsonrpc": "2.0",
478	        "id": id.unwrap_or(Value::Null),
479	        "result": result
480	    })
481	}
482	
483	fn json_rpc_error(id: Option<Value>, code: i32, message: &str) -> Value {
484	    json!({
485	        "jsonrpc": "2.0",
486	        "id": id.unwrap_or(Value::Null),
487	        "error": {
488	            "code": code,
489	            "message": message
490	        }
491	    })
492	}
