494	#[cfg(test)]
495	mod tests {
496	    use super::*;
497	
498	    #[test]
499	    fn test_json_rpc_result_format() {
500	        let result = json_rpc_result(Some(json!(1)), json!({"ok": true}));
501	        assert_eq!(result["jsonrpc"], "2.0");
502	        assert_eq!(result["id"], 1);
503	        assert_eq!(result["result"]["ok"], true);
504	    }
505	
506	    #[test]
507	    fn test_json_rpc_error_format() {
508	        let error = json_rpc_error(Some(json!(2)), -32601, "Not found");
509	        assert_eq!(error["jsonrpc"], "2.0");
510	        assert_eq!(error["id"], 2);
511	        assert_eq!(error["error"]["code"], -32601);
512	    }
513	}
