41	/// The gRPC server. Created once at daemon startup, runs until shutdown.
42	pub struct IpcServer {
43	    sessions: SessionManager,
44	    goals: GoalManager,
45	    events: Arc<EventBus>,
46	    decisions: ans_storage::DecisionStore,
47	    budget: std::sync::Arc<tokio::sync::Mutex<ans_budget::BudgetTracker>>,
48	    signal_router: SignalRouter,
49	    metrics: Arc<Metrics>,
50	}
51	
52	impl IpcServer {
53	    #[must_use]
54	    pub fn new() -> Self {
55	        Self {
56	            sessions: SessionManager::new(),
57	            goals: GoalManager::new(),
58	            events: Arc::new(EventBus::new()),
59	            decisions: ans_storage::DecisionStore::new(),
60	            budget: std::sync::Arc::new(tokio::sync::Mutex::new(
61	                ans_budget::BudgetTracker::default(),
62	            )),
63	            signal_router: SignalRouter::new(),
64	            metrics: Arc::new(Metrics::new()),
65	        }
66	    }
67	
68	    /// New with a shared metrics handle (from gateway).
69	    #[must_use]
