72	            sessions: SessionManager::new(),
73	            goals: GoalManager::new(),
74	            events: Arc::new(EventBus::new()),
75	            decisions: ans_storage::DecisionStore::new(),
76	            budget: std::sync::Arc::new(tokio::sync::Mutex::new(
77	                ans_budget::BudgetTracker::default(),
78	            )),
