794	#[allow(clippy::result_large_err)]
795	fn proto_to_core_action(
796	    proto: &ans_proto::ans::Action,
797	) -> Result<ans_core::session::Action, Status> {
798	    use ans_core::session::ActionType;
799	    use std::collections::HashMap;
800	
801	    let action_type = match proto.action_type.as_str() {
802	        "click" => ActionType::Click,
803	        "type" => ActionType::Type,
804	        "scroll" => ActionType::Scroll,
805	        "select" => ActionType::Select,
806	        "navigate" => ActionType::Navigate,
807	        "wait" => ActionType::Wait,
808	        "submit" => ActionType::Submit,
809	        "screenshot" => ActionType::Screenshot,
810	        other => {
811	            return Err(Status::invalid_argument(format!(
812	                "unknown action_type: {other}"
813	            )))
814	        }
815	    };
816	
817	    Ok(ans_core::session::Action {
818	        action_type,
819	        selector: optional_string(&proto.selector),
820	        value: optional_string(&proto.value),
821	        params: proto
822	            .params
823	            .iter()
824	            .map(|(k, v)| (k.clone(), v.clone()))
825	            .collect::<HashMap<_, _>>(),
826	    })
827	}
