1	//! Internal gRPC client for forwarding gateway requests to the
2	//! Agent Nervous System daemon on port 50051.
3	
4	use ans_proto::ans::agent_nervous_system_client::AgentNervousSystemClient;
5	use tonic::transport::Channel;
6	
7	/// Wrapper around the internal gRPC client.
8	///
9	/// Created once at gateway startup. All protocol adapters (MCP, REST,
10	/// WebSocket) share this client to forward requests to the daemon.
11	#[derive(Clone)]
12	pub struct InternalClient {
13	    inner: AgentNervousSystemClient<Channel>,
14	}
15	
16	impl InternalClient {
17	    /// Connect to the local gRPC server.
18	    pub async fn connect() -> Result<Self, tonic::transport::Error> {
19	        let channel = Channel::from_static("http://127.0.0.1:50051")
20	            .connect()
21	            .await?;
