// In tool_create_goal, use hardcoded defaults:
async fn tool_create_goal(&self, args: &Value) -> Result<String, String> {
    let description = Self::str_arg(args, "description").ok_or("description required")?;
    let context_str = Self::str_arg(args, "context").unwrap_or("");

    let mut context = std::collections::HashMap::new();
    if !context_str.is_empty() {
        context.insert("context".into(), context_str.into());
    }

    let mut client = self.client.clone_client();
    let req = tonic::Request::new(ans_proto::ans::CreateGoalRequest {
        description: description.into(),
        context,
        max_budget_cents: 500,   // internal default
        max_steps: 50,           // internal default
    });
    // ... rest unchanged
