async fn create_goal(&self, request: Request<CreateGoalRequest>) -> Result<Response<GoalState>, Status> {
    let req = request.into_inner();
    let state = self.goals.create_goal(&req.description, &req.context, req.max_steps as u32)
        .map_err(|e| Status::internal(e.to_string()))?;

    self.metrics.inc_goals(1);

    // ── Spawn Python intelligence in background ──────────────────
    let goal_id = state.goal_id.to_string();
    let description = state.description.clone();

    let mut cmd = tokio::process::Command::new("python");
    cmd.args(["-m", "ans_nerves", "run", "--goal-id", &goal_id, &description])
       .kill_on_drop(true);

    // Set PYTHONPATH if nerves_dir configured
    if let Some(ref dir) = self.nerves_dir {
        cmd.env("PYTHONPATH", dir);
        cmd.current_dir(dir);
    }

    tokio::spawn(async move {
        match cmd.output().await {
            Ok(output) => {
                if output.status.success() {
                    tracing::info!(%goal_id, "Python AgentLoop completed successfully");
                } else {
                    let stderr = String::from_utf8_lossy(&output.stderr);
                    tracing::error!(%goal_id, %stderr, "Python AgentLoop failed");
                }
            }
            Err(e) => {
                tracing::error!(%goal_id, error=%e, "Failed to spawn Python AgentLoop");
            }
        }
    });

    Ok(Response::new(ans_goal::serialization::goal_state_to_proto(&state)))
}
```

### 6. `crates/ans-daemon/src/main.rs` — Pass `nerves_dir` to IpcServer

**Why**: The daemon needs to tell the IPC server where the Python package lives so it can set `PYTHONPATH` when spawning the Python process.

**Changes**:
- Add `--nerves-dir` CLI argument (default: auto-detect from CWD `./nerves`)
- Pass it to `IpcServer::new().with_nerves_dir(...)`

```rust
#[derive(Parser)]
struct Cli {
    // ... existing args ...
    /// Path to nerves/ans_nerves Python package directory
    #[arg(long, default_value = "nerves")]
    nerves_dir: PathBuf,
}

// In main():
let nerves_abs = if cli.nerves_dir.is_absolute() {
    cli.nerves_dir.clone()
} else {
    std::env::current_dir().unwrap_or_default().join(&cli.nerves_dir)
};

let server = IpcServer::new().with_nerves_dir(nerves_abs);
```

